SELECT AVG(vat_rate) AS average_vat_rate
FROM vat_rates
WHERE country_id = 0;

SELECT analysis_type, AVG(price_difference) AS average_price_difference
FROM price_analysis
GROUP BY analysis_type;

SELECT local_price
FROM pricing
WHERE pricing_id = 0;

SELECT vat_rate
FROM vat_rates
WHERE country_id = 0;
